-- SQL Schema for Pnlgrok Database \n\n-- Users Table\nCREATE TABLE users (\n    id SERIAL PRIMARY KEY,\n    username VARCHAR(50) NOT NULL UNIQUE,\n    password_hash VARCHAR(255) NOT NULL,\n    email VARCHAR(100) NOT NULL UNIQUE,\n    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Transactions Table\nCREATE TABLE transactions (\n    id SERIAL PRIMARY KEY,\n    user_id INT NOT NULL,\n    amount DECIMAL(10, 2) NOT NULL,\n    transaction_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE\n);\n\n-- Audit Table\nCREATE TABLE audit_log (\n    id SERIAL PRIMARY KEY,\n    action VARCHAR(255) NOT NULL,\n    user_id INT NOT NULL,\n    timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\n    FOREIGN KEY (user_id) REFERENCES users(id)\n);\n\n-- Function for Atomic Transactions\nCREATE OR REPLACE FUNCTION perform_transaction(user_id INT, trans_amount DECIMAL) RETURNS VOID AS $\n$$\nDECLARE\n    transaction_id INT;\nbegin\n    -- Start a transaction\n    BEGIN\n        -- Insert a new transaction\n        INSERT INTO transactions (user_id, amount) VALUES (user_id, trans_amount) RETURNING id INTO transaction_id;\n        -- Log the transaction in the audit log\n        INSERT INTO audit_log (action, user_id) VALUES ('Transaction created with ID ' || transaction_id, user_id);\n    EXCEPTION\n        WHEN OTHERS THEN\n            -- Handle errors\n            ROLLBACK;\n            RAISE;\n    END;\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Security Policies\n-- Example: Restrict access based on user roles\nCREATE ROLE app_user;\nCREATE ROLE app_admin;\n-- Grant permissions to roles as necessary\nGRANT SELECT, INSERT, UPDATE ON users TO app_user;\nGRANT ALL PRIVILEGES ON transactions TO app_admin;\n\n-- Audit Trail Policy\nCREATE OR REPLACE FUNCTION log_audit(action VARCHAR, uid INT) RETURNS VOID AS $\n$$\nbegin\n    INSERT INTO audit_log(action, user_id) VALUES (action, uid);\nEND;\n$$ LANGUAGE plpgsql;